/**
 * Lightweight JSON Schema validator with human-readable error messages.
 *
 * Supports: type, const, enum, required, properties, additionalProperties,
 * minLength, maxLength, pattern, minimum, maximum, minItems, maxItems,
 * items, oneOf, anyOf, allOf, not.
 */

// ─── Schema & Input ──────────────────────────────────────────────────
const requiredSchema = $input.first().json.requiredSchema;
const jsonToValidate = $input.first().json.paramsToValidate;

// ─── Helpers ─────────────────────────────────────────────────────────

/**
 * Creates an error object with a path, message, and optional description.
 * Keeps internal metadata separate from user-facing fields via _meta.
 */
function makeError(path, message, schema = {}, meta = {}) {
  const error = { path, message };
  if (schema.description) error.description = schema.description;
  if (Object.keys(meta).length) error._meta = meta;
  return error;
}

/**
 * Returns the human-readable type name for a value.
 * Distinguishes arrays, null, and NaN from generic typeof results.
 */
function getTypeName(value) {
  if (value === null) return "null";
  if (Array.isArray(value)) return "array";
  if (typeof value === "number" && isNaN(value)) return "NaN";
  return typeof value;
}

/**
 * Checks if a value matches JSON Schema's "integer" type.
 * Must be a finite number with no fractional part. NaN fails.
 */
function isInteger(value) {
  return typeof value === "number" && Number.isFinite(value) && Math.floor(value) === value;
}

/**
 * Checks if a value is a valid, finite number.
 * Rejects NaN, Infinity, and -Infinity — none are meaningful
 * in the context of JSON Schema numeric constraints.
 */
function isValidNumber(value) {
  return typeof value === "number" && Number.isFinite(value);
}

/**
 * Checks whether the given value is a plain object (not null, not an array).
 * Used for schema shape validation and internal type guards.
 */
function isPlainObject(value) {
  return typeof value === "object" && value !== null && !Array.isArray(value);
}

/**
 * Deep equality comparison for JSON-compatible values.
 * Handles primitives, arrays, and plain objects recursively.
 * Used by checkEnum so objects/arrays are compared by structure, not reference.
 */
function deepEqual(a, b) {
  if (a === b) return true;
  if (a === null || b === null) return false;
  if (typeof a !== typeof b) return false;

  if (Array.isArray(a)) {
    if (!Array.isArray(b) || a.length !== b.length) return false;
    return a.every((val, i) => deepEqual(val, b[i]));
  }

  if (typeof a === "object") {
    if (Array.isArray(b)) return false;
    const keysA = Object.keys(a);
    const keysB = Object.keys(b);
    if (keysA.length !== keysB.length) return false;
    return keysA.every((key) => Object.prototype.hasOwnProperty.call(b, key) && deepEqual(a[key], b[key]));
  }

  return false;
}

/**
 * Safely tests a string against a regex pattern.
 * Returns { match: boolean, error?: string }.
 * Catches malformed regex patterns instead of crashing.
 */
function safeRegexTest(pattern, value) {
  try {
    return { match: new RegExp(pattern).test(value) };
  } catch (e) {
    return { match: false, error: `Invalid regex pattern: ${pattern}` };
  }
}

/**
 * Pluralizes "Field"/"is" based on count for error messages.
 * e.g. formatFieldList(["a"]) -> 'Field "a" is'
 *      formatFieldList(["a","b"]) -> 'Fields "a", "b" are'
 */
function formatFieldList(fields) {
  const quoted = fields.map((f) => `"${f}"`).join(", ");
  return fields.length === 1
    ? `Field ${quoted} is`
    : `Fields ${quoted} are`;
}

/**
 * Extracts const-based context from a oneOf variant schema.
 * Returns a "when x is y" clause for enriching error messages.
 *
 * e.g. { properties: { type: { const: "free_product" } } }
 *   -> ' when type is "free_product"'
 */
function buildWhenClause(variantSchema) {
  const pairs = [];
  for (const [key, propSchema] of Object.entries(variantSchema.properties || {})) {
    if (propSchema.const !== undefined) {
      pairs.push(`${key} is "${propSchema.const}"`);
    }
  }
  return pairs.length ? ` when ${pairs.join(" and ")}` : "";
}

/**
 * Checks whether a value is explicitly nullable in the schema.
 * Handles both enum and const allowing null.
 */
function isNullAllowed(schema) {
  if (schema.const === null) return true;
  if (Array.isArray(schema.enum) && schema.enum.some((v) => deepEqual(v, null))) return true;
  return false;
}

/**
 * Builds a child path by appending a property key to a parent path.
 * Handles the root case (empty parent) so we get "name" instead of ".name".
 */
function joinPath(parent, key) {
  return parent ? `${parent}.${key}` : key;
}

/**
 * Builds a child path by appending an array index to a parent path.
 * Handles the root case (empty parent) so we get "[0]" instead of ".[0]".
 */
function indexPath(parent, index) {
  return `${parent}[${index}]`;
}

// ─── Type Validators ─────────────────────────────────────────────────

/**
 * Validates that the data's type matches the schema's declared type.
 * Handles the "integer" type that JSON Schema supports but JS typeof doesn't.
 * Rejects NaN and Infinity as invalid numbers.
 */
function checkType(schema, data, at) {
  if (!schema.type) return [];

  const actual = getTypeName(data);

  // "integer" is a special case — typeof returns "number" for both ints and floats
  if (schema.type === "integer") {
    if (!isInteger(data)) {
      const display = actual === "number" ? "non-integer number" : actual;
      return [makeError(at, `Expected type "integer" but got "${display}"`, schema)];
    }
    return [];
  }

  // NaN technically has typeof "number" but is never a valid number
  if (schema.type === "number" && actual === "NaN") {
    return [makeError(at, `Expected type "number" but got NaN`, schema)];
  }

  // Infinity/-Infinity are typeof "number" but not finite.
  // Reject them at the type level so they don't silently pass through.
  if (schema.type === "number" && !Number.isFinite(data)) {
    return [makeError(at, `Expected a finite number but got ${data}`, schema)];
  }

  if (actual !== schema.type) {
    return [makeError(at, `Expected type "${schema.type}" but got "${actual}"`, schema)];
  }
  return [];
}

/**
 * Validates string-specific constraints: minLength, maxLength, pattern.
 * Falls back to description for pattern errors when available.
 * Catches invalid regex patterns gracefully.
 */
function checkString(schema, data, at) {
  if (typeof data !== "string") return [];
  const errors = [];

  if (schema.minLength !== undefined && data.length < schema.minLength) {
    const msg = schema.minLength === 1
      ? "Must not be empty"
      : `Must be at least ${schema.minLength} character(s) long, got ${data.length}`;
    errors.push(makeError(at, msg, schema));
  }

  if (schema.maxLength !== undefined && data.length > schema.maxLength) {
    errors.push(makeError(at, `Must be at most ${schema.maxLength} character(s) long, got ${data.length}`, schema));
  }

  // Pattern: use safeRegexTest to avoid crashing on malformed patterns
  if (schema.pattern) {
    const result = safeRegexTest(schema.pattern, data);
    if (result.error) {
      // Malformed regex in schema — report as a schema error
      errors.push(makeError(at, result.error));
    } else if (!result.match) {
      // Prefer description over raw regex in the message
      const msg = schema.description
        ? `"${data}" is not valid — expected: ${schema.description}`
        : `"${data}" does not match required pattern: ${schema.pattern}`;
      errors.push(makeError(at, msg));
    }
  }

  return errors;
}

/**
 * Validates number-specific constraints: minimum, maximum,
 * exclusiveMinimum, exclusiveMaximum.
 * Runs for both "number" and "integer" schema types.
 */
function checkNumber(schema, data, at) {
  if (!isValidNumber(data)) return [];
  const errors = [];

  if (schema.minimum !== undefined && data < schema.minimum)
    errors.push(makeError(at, `Must be at least ${schema.minimum}, got ${data}`, schema));
  if (schema.maximum !== undefined && data > schema.maximum)
    errors.push(makeError(at, `Must be at most ${schema.maximum}, got ${data}`, schema));
  if (schema.exclusiveMinimum !== undefined && data <= schema.exclusiveMinimum)
    errors.push(makeError(at, `Must be greater than ${schema.exclusiveMinimum}, got ${data}`, schema));
  if (schema.exclusiveMaximum !== undefined && data >= schema.exclusiveMaximum)
    errors.push(makeError(at, `Must be less than ${schema.exclusiveMaximum}, got ${data}`, schema));

  return errors;
}

/**
 * Validates enum constraint — value must be one of the listed options.
 * Uses deepEqual so objects and arrays are compared by structure, not reference.
 */
function checkEnum(schema, data, at) {
  if (!schema.enum) return [];
  if (schema.enum.some((allowed) => deepEqual(allowed, data))) return [];
  return [makeError(at, `"${data}" is not an allowed value. Must be one of: ${schema.enum.join(", ")}`, schema)];
}

/**
 * Validates const constraint — value must exactly equal the specified constant.
 */
function checkConst(schema, data, at) {
  if (schema.const === undefined) return [];
  if (data === schema.const) return [];
  return [makeError(at, `Must be "${schema.const}" but got "${data}"`, schema)];
}

// ─── Composite Validators ────────────────────────────────────────────

/**
 * Validates array-specific constraints: minItems, maxItems, and
 * recursively validates each item against the items schema.
 * Attaches the raw value to leaf-level errors for context.
 *
 * Container-level errors (minItems, maxItems) use `label` so root-level
 * arrays get a readable path instead of an empty string.
 * Child item paths still use raw `at` for clean indexing (e.g. "[0]").
 */
function checkArray(schema, data, at) {
  if (!Array.isArray(data)) return [];
  const errors = [];
  const label = at || "root";

  if (schema.minItems !== undefined && data.length < schema.minItems)
    errors.push(makeError(label, `Must have at least ${schema.minItems} item(s), got ${data.length}`, schema));
  if (schema.maxItems !== undefined && data.length > schema.maxItems)
    errors.push(makeError(label, `Must have at most ${schema.maxItems} item(s), got ${data.length}`, schema));

  if (schema.items) {
    data.forEach((item, i) => {
      const itemErrors = validate(schema.items, item, indexPath(at, i));
      // Attach raw value for non-object items so the final message shows what was received
      itemErrors.forEach((e) => {
        if (e.value === undefined && typeof item !== "object") e.value = item;
      });
      errors.push(...itemErrors);
    });
  }

  return errors;
}

/**
 * Validates object-specific constraints: required fields, property schemas,
 * and additionalProperties.
 *
 * When additionalProperties is false with no properties defined,
 * treats the allowed set as empty (rejects all keys).
 *
 * Validates that schema.required is an array before iterating. A bare string
 * like "name" would be iterated character-by-character by for..of, producing
 * nonsensical "missing field 'n'" errors.
 */
function checkObject(schema, data, at) {
  if (typeof data !== "object" || data === null || Array.isArray(data)) return [];
  if (!schema.properties && !schema.required && schema.additionalProperties === undefined) return [];

  const errors = [];

  // Guard against non-array required (e.g. required: "name")
  if (schema.required !== undefined && !Array.isArray(schema.required)) {
    errors.push(makeError(at || "root", `Schema error: "required" must be an array, got ${getTypeName(schema.required)}`));
  } else {
    // Required fields
    for (const key of schema.required || []) {
      if (!(key in data)) {
        const propSchema = schema.properties?.[key] || {};
        errors.push(makeError(joinPath(at, key), `Missing required field "${key}"`, propSchema));
      }
    }
  }

  // Validate each declared property that exists on the data
  for (const [key, propSchema] of Object.entries(schema.properties || {})) {
    if (key in data) {
      errors.push(...validate(propSchema, data[key], joinPath(at, key)));
    }
  }

  // Reject undeclared properties when additionalProperties is false.
  // If properties is not defined, treat allowed set as empty — all keys rejected.
  if (schema.additionalProperties === false) {
    const allowed = new Set(Object.keys(schema.properties || {}));
    for (const key of Object.keys(data)) {
      if (!allowed.has(key)) {
        errors.push(makeError(joinPath(at, key), `Unknown field "${key}" is not allowed`));
      }
    }
  }

  return errors;
}

// ─── Logical Combinators ─────────────────────────────────────────────

/**
 * Validates the "not" keyword.
 * The data is valid only if it FAILS the inner schema.
 * Reports which forbidden fields were found.
 * Handles generic "not" schemas beyond just "not.required".
 */
function checkNot(schema, data, at) {
  if (!schema.not) return [];

  const innerErrors = validate(schema.not, data, at);
  const label = at || "root";

  // If inner schema produced errors, the "not" passes (data doesn't match the forbidden schema)
  if (innerErrors.length > 0) return [];

  // Data matched the forbidden schema — figure out what to report
  const errors = [];

  // Case 1: not.required — specific forbidden fields present in the data
  if (Array.isArray(schema.not.required) && typeof data === "object" && data !== null) {
    const present = schema.not.required.filter((k) => k in data);
    if (present.length) {
      errors.push(makeError(label, `${formatFieldList(present)} not allowed here`, {}, { forbidden: present }));
    }
  }

  // Case 2: generic not (no required, or no forbidden fields found) — general message
  if (errors.length === 0) {
    errors.push(makeError(label, "Value must not match the excluded schema"));
  }

  return errors;
}

/**
 * Validates the "oneOf" keyword using best-match strategy.
 *
 * 1. If exactly one variant matches perfectly, pass.
 * 2. If multiple match, report ambiguity.
 * 3. If none match, pick the closest variant (fewest errors, with a
 *    tiebreaker favoring variants where const fields match the data)
 *    and surface only its errors, enriched with "when" context.
 *
 * Handles empty oneOf arrays gracefully.
 */
function checkOneOf(schema, data, at) {
  if (!schema.oneOf) return [];

  const label = at || "root";

  // Edge case: empty oneOf means nothing can match
  if (schema.oneOf.length === 0) {
    return [makeError(label, "No variants defined in oneOf — nothing can match")];
  }

  const results = schema.oneOf.map((sub) => ({
    schema: sub,
    errors: validate(sub, data, at),
  }));

  const perfect = results.filter((r) => r.errors.length === 0);

  // Exactly one match — valid
  if (perfect.length === 1) return [];

  // Multiple matches — ambiguous
  if (perfect.length > 1) {
    return [makeError(label, "Ambiguous — matches multiple variants when only one is allowed")];
  }

  // No match — find best fit using const-match tiebreaker.
  // Const matches heavily reduce score so the variant matching
  // the user's intent always wins ties.
  const scored = results.map((r) => {
    let constMatches = 0;
    for (const [key, propSchema] of Object.entries(r.schema.properties || {})) {
      if (
        propSchema.const !== undefined &&
        typeof data === "object" &&
        data !== null &&
        data[key] === propSchema.const
      ) {
        constMatches++;
      }
    }
    return { ...r, score: r.errors.length - constMatches * (results.length + 1) };
  });
  scored.sort((a, b) => a.score - b.score);

  const best = scored[0];
  const whenClause = buildWhenClause(best.schema);

  // Enrich errors with context and filter out noise (const mismatch errors)
  const enriched = best.errors
    .filter((e) => !e.message.startsWith('Must be "'))
    .map((e) => {
      const forbidden = e._meta?.forbidden;

      if (forbidden && whenClause) {
        // Preserve description from original error if present
        const enrichedSchema = e.description ? { description: e.description } : {};
        return makeError(e.path, `${formatFieldList(forbidden)} not allowed${whenClause}`, enrichedSchema);
      }
      if (e.message.includes("Missing required field") && whenClause) {
        const enrichedSchema = e.description ? { description: e.description } : {};
        return makeError(e.path, `${e.message}${whenClause}`, enrichedSchema);
      }
      return e;
    });

  if (enriched.length) return enriched;

  // Fallback: couldn't isolate clear errors from best match
  const summary = results.map((r) => {
    const constEntry = Object.entries(r.schema.properties || {}).find(([, v]) => v.const !== undefined);
    const name = constEntry ? constEntry[1].const : "unknown";
    return `"${name}": ${r.errors.map((e) => e.message).join("; ")}`;
  });
  return [makeError(label, `Does not match any allowed variant: ${summary.join(" | ")}`)];
}

/**
 * Validates "anyOf" — at least one subschema must match.
 */
function checkAnyOf(schema, data, at) {
  if (!schema.anyOf) return [];
  const anyMatch = schema.anyOf.some((sub) => validate(sub, data, at).length === 0);
  if (anyMatch) return [];
  return [makeError(at || "root", "Does not match any allowed option", schema)];
}

/**
 * Validates "allOf" — every subschema must match.
 */
function checkAllOf(schema, data, at) {
  if (!schema.allOf) return [];
  return schema.allOf.flatMap((sub) => validate(sub, data, at));
}

// ─── Main Validator ──────────────────────────────────────────────────

/**
 * Recursively validates data against a JSON Schema.
 * Returns an array of error objects. Empty array = valid.
 *
 * Path starts as "" (root). Child paths are built via joinPath/indexPath
 * so top-level fields appear as "name" not "root.name", while nested
 * fields read naturally as "address.street" or "tags[0]".
 * Only true root-level errors (e.g. wrong top-level type) show as "root".
 *
 * Handles null/undefined before type checking because typeof null === "object" in JS.
 * Allows null/undefined when explicitly permitted by const or enum.
 *
 * Rejects non-plain-object schemas up front instead of silently
 * passing everything or crashing on null.
 *
 * When schema.const is defined, enum is skipped. const is strictly
 * more specific (single value) and subsumes enum.
 */
function validate(schema, data, path = "") {
  const at = path;

  // Schema shape guard — reject anything that isn't a plain object.
  // Catches null, undefined, strings, numbers, booleans, and arrays, all of
  // which would either crash or silently produce zero errors.
  if (!isPlainObject(schema)) {
    return [makeError(at || "root", `Invalid schema: expected a plain object, got ${getTypeName(schema)}`)];
  }

  // Null/undefined: allow if schema explicitly permits it via const or enum,
  // otherwise reject early before type check (typeof null === "object" in JS)
  if (data === null || data === undefined) {
    if (isNullAllowed(schema)) {
      // null is explicitly valid here — still check const/enum but skip everything else
      const errors = [...checkConst(schema, data, at || "root")];
      // Skip enum when const is defined — const subsumes enum
      if (schema.const === undefined) errors.push(...checkEnum(schema, data, at || "root"));
      return errors;
    }
    return [makeError(at || "root", "Field is missing or null", schema)];
  }

  // Type check (gates further validation — wrong type means deeper checks are meaningless)
  const typeErrors = checkType(schema, data, at || "root");
  if (typeErrors.length) return typeErrors;

  // When const is defined, it's the authoritative value check —
  // enum is redundant and potentially contradictory. Skip it.
  const enumErrors = schema.const !== undefined ? [] : checkEnum(schema, data, at || "root");

  // Run all validators and collect errors
  return [
    ...checkConst(schema, data, at || "root"),
    ...checkString(schema, data, at || "root"),
    ...checkNumber(schema, data, at || "root"),
    ...enumErrors,
    ...checkArray(schema, data, at),
    ...checkObject(schema, data, at),
    ...checkNot(schema, data, at),
    ...checkOneOf(schema, data, at),
    ...checkAnyOf(schema, data, at),
    ...checkAllOf(schema, data, at),
  ];
}

// ─── Format & Output ─────────────────────────────────────────────────

/**
 * Formats a single error object into a readable bullet line.
 * Includes the raw value if present, and appends description when
 * it adds context beyond what's already in the message.
 */
function formatError(error) {
  let line = `• ${error.path}: ${error.message}`;
  if (error.value !== undefined) line += ` (got: "${error.value}")`;
  if (error.description && !error.message.includes(error.description)) line += ` — ${error.description}`;
  return line;
}

/**
 * Strips internal metadata (_meta) from error objects
 * so it never leaks into the output.
 */
function cleanErrors(errors) {
  return errors.map(({ _meta, ...rest }) => rest);
}

// ─── Run ─────────────────────────────────────────────────────────────

let output;

try {
  const errors = validate(requiredSchema, jsonToValidate);

  if (errors.length) {
    const msg = cleanErrors(errors).map(formatError).join("\n");

    output = {
      valid: false,
      validationError: `Validation failed (${errors.length} issue${errors.length > 1 ? "s" : ""}):\n${msg}`,
      requiredSchema: JSON.parse(JSON.stringify(requiredSchema)),
    };
  } else {
    output = {
      valid: true,
      validationError: null,
    };
  }
} catch (error) {
  output = {
    valid: false,
    validationError: `Validator error: ${error.message}`,
  };
}

return output;

